import{_ as i,o as e,c as s,ae as o}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"메모리 개요","description":"OpenClaw가 세션 간에 것들을 기억하는 방법","frontmatter":{"title":"메모리 개요","description":"OpenClaw가 세션 간에 것들을 기억하는 방법"},"headers":[],"relativePath":"concepts/memory.md","filePath":"concepts/memory.md","lastUpdated":null}'),l={name:"concepts/memory.md"};function t(n,a,c,r,p,h){return e(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="메모리-개요" tabindex="-1">메모리 개요 <a class="header-anchor" href="#메모리-개요" aria-label="Permalink to &quot;메모리 개요&quot;">​</a></h1><p>OpenClaw는 에이전트의 워크스페이스에 <strong>일반 마크다운 파일</strong>을 작성하여 것들을 기억합니다. 모델은 디스크에 저장된 것만 &quot;기억합니다&quot; -- 숨겨진 상태는 없습니다.</p><h2 id="작동-방식" tabindex="-1">작동 방식 <a class="header-anchor" href="#작동-방식" aria-label="Permalink to &quot;작동 방식&quot;">​</a></h2><p>에이전트에는 메모리와 관련된 세 가지 파일이 있습니다:</p><ul><li><strong><code>MEMORY.md</code></strong> -- 장기 메모리. 내구성 있는 사실, 선호도, 결정. 모든 DM 세션 시작 시 로드됩니다.</li><li><strong><code>memory/YYYY-MM-DD.md</code></strong> -- 일별 메모. 실행 중인 컨텍스트와 관찰. 오늘과 어제의 메모가 자동으로 로드됩니다.</li><li><strong><code>DREAMS.md</code></strong> (실험적, 선택적) -- Dream Diary 및 드리밍 스윕 요약 (기반 히스토리 백필 항목 포함)을 사람이 검토합니다.</li></ul><p>이 파일들은 에이전트 워크스페이스 (기본값 <code>~/.openclaw/workspace</code>)에 있습니다.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>에이전트가 무언가를 기억하기를 원하면 그냥 물어보십시오: &quot;TypeScript를 선호한다는 것을 기억해.&quot; 에이전트가 적절한 파일에 씁니다.</p></div><h2 id="메모리-도구" tabindex="-1">메모리 도구 <a class="header-anchor" href="#메모리-도구" aria-label="Permalink to &quot;메모리 도구&quot;">​</a></h2><p>에이전트에는 메모리 작업을 위한 두 가지 도구가 있습니다:</p><ul><li><strong><code>memory_search</code></strong> -- 표현이 원본과 다를 때도 시맨틱 검색을 사용하여 관련 메모를 찾습니다.</li><li><strong><code>memory_get</code></strong> -- 특정 메모리 파일 또는 라인 범위를 읽습니다.</li></ul><p>두 도구 모두 활성 메모리 플러그인 (기본값: <code>memory-core</code>)이 제공합니다.</p><h2 id="메모리-위키-컴패니언-플러그인" tabindex="-1">메모리 위키 컴패니언 플러그인 <a class="header-anchor" href="#메모리-위키-컴패니언-플러그인" aria-label="Permalink to &quot;메모리 위키 컴패니언 플러그인&quot;">​</a></h2><p>내구성 있는 메모리가 원시 메모보다 유지 관리되는 지식 베이스처럼 동작하기를 원한다면 번들된 <code>memory-wiki</code> 플러그인을 사용하십시오.</p><p><code>memory-wiki</code>는 내구성 있는 지식을 다음과 같은 위키 볼트로 컴파일합니다:</p><ul><li>결정론적 페이지 구조</li><li>구조화된 주장 및 증거</li><li>모순 및 신선도 추적</li><li>생성된 대시보드</li><li>에이전트/런타임 소비자를 위한 컴파일된 요약</li><li><code>wiki_search</code>, <code>wiki_get</code>, <code>wiki_apply</code>, <code>wiki_lint</code> 같은 위키 네이티브 도구</li></ul><p>이는 활성 메모리 플러그인을 대체하지 않습니다. 활성 메모리 플러그인은 여전히 회상, 승격, 드리밍을 소유합니다. <code>memory-wiki</code>는 옆에 출처가 풍부한 지식 레이어를 추가합니다.</p><p><a href="/openclaw-docs-ko/plugins/memory-wiki">메모리 위키</a>를 참조하십시오.</p><h2 id="메모리-검색" tabindex="-1">메모리 검색 <a class="header-anchor" href="#메모리-검색" aria-label="Permalink to &quot;메모리 검색&quot;">​</a></h2><p>임베딩 프로바이더가 구성된 경우, <code>memory_search</code>는 <strong>하이브리드 검색</strong> -- 벡터 유사성 (시맨틱 의미)과 키워드 매칭 (ID 및 코드 기호 같은 정확한 용어)을 결합 -- 을 사용합니다. 지원되는 프로바이더의 API 키가 있으면 즉시 작동합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>OpenClaw는 사용 가능한 API 키에서 임베딩 프로바이더를 자동 감지합니다. OpenAI, Gemini, Voyage, 또는 Mistral 키가 구성되어 있으면 메모리 검색이 자동으로 활성화됩니다.</p></div><p>검색 작동 방식, 조정 옵션, 프로바이더 설정은 <a href="/openclaw-docs-ko/concepts/memory-search">메모리 검색</a>을 참조하십시오.</p><h2 id="메모리-백엔드" tabindex="-1">메모리 백엔드 <a class="header-anchor" href="#메모리-백엔드" aria-label="Permalink to &quot;메모리 백엔드&quot;">​</a></h2><blockquote><p><strong>내장 (기본값)</strong> SQLite 기반. 키워드 검색, 벡터 유사성, 하이브리드 검색으로 즉시 작동합니다. 추가 종속성 없습니다.</p></blockquote><blockquote><p><strong>QMD</strong> 재순위화, 쿼리 확장, 워크스페이스 외부 디렉터리 인덱싱 기능이 있는 로컬 우선 사이드카.</p></blockquote><blockquote><p><strong>Honcho</strong> 사용자 모델링, 시맨틱 검색, 멀티 에이전트 인식이 있는 AI 네이티브 크로스 세션 메모리. 플러그인 설치 필요.</p></blockquote><h2 id="지식-위키-레이어" tabindex="-1">지식 위키 레이어 <a class="header-anchor" href="#지식-위키-레이어" aria-label="Permalink to &quot;지식 위키 레이어&quot;">​</a></h2><blockquote><p><strong>메모리 위키</strong> 내구성 있는 메모리를 주장, 대시보드, 브리지 모드, Obsidian 친화적 워크플로우가 있는 출처 풍부한 위키 볼트로 컴파일합니다.</p></blockquote><h2 id="자동-메모리-플러시" tabindex="-1">자동 메모리 플러시 <a class="header-anchor" href="#자동-메모리-플러시" aria-label="Permalink to &quot;자동 메모리 플러시&quot;">​</a></h2><p><a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a>이 대화를 요약하기 전에 OpenClaw는 에이전트에게 중요한 컨텍스트를 메모리 파일에 저장하도록 상기시키는 자동 턴을 실행합니다. 이는 기본적으로 켜져 있습니다 -- 아무것도 구성할 필요가 없습니다.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>메모리 플러시는 컴팩션 중 컨텍스트 손실을 방지합니다. 에이전트가 아직 파일에 쓰지 않은 중요한 사실이 대화에 있다면, 요약이 발생하기 전에 자동으로 저장됩니다.</p></div><h2 id="드리밍-실험적" tabindex="-1">드리밍 (실험적) <a class="header-anchor" href="#드리밍-실험적" aria-label="Permalink to &quot;드리밍 (실험적)&quot;">​</a></h2><p>드리밍은 메모리를 위한 선택적 백그라운드 통합 패스입니다. 단기 신호를 수집하고, 후보를 점수화하며, 자격을 갖춘 항목만 장기 메모리 (<code>MEMORY.md</code>)로 승격합니다.</p><p>장기 메모리를 고품질로 유지하도록 설계되었습니다:</p><ul><li><strong>옵트인</strong>: 기본적으로 비활성화됨.</li><li><strong>예약됨</strong>: 활성화되면 <code>memory-core</code>가 전체 드리밍 스윕을 위한 하나의 반복 크론 잡을 자동 관리합니다.</li><li><strong>임계값 적용</strong>: 승격은 점수, 회상 빈도, 쿼리 다양성 게이트를 통과해야 합니다.</li><li><strong>검토 가능</strong>: 단계 요약 및 일기 항목이 사람이 검토할 수 있도록 <code>DREAMS.md</code>에 씁니다.</li></ul><p>단계 동작, 점수화 신호, Dream Diary 세부사항은 <a href="/openclaw-docs-ko/concepts/dreaming">드리밍 (실험적)</a>을 참조하십시오.</p><h2 id="기반-백필-및-라이브-승격" tabindex="-1">기반 백필 및 라이브 승격 <a class="header-anchor" href="#기반-백필-및-라이브-승격" aria-label="Permalink to &quot;기반 백필 및 라이브 승격&quot;">​</a></h2><p>드리밍 시스템에는 이제 두 가지 밀접하게 관련된 검토 레인이 있습니다:</p><ul><li><strong>라이브 드리밍</strong>은 <code>memory/.dreams/</code> 아래의 단기 드리밍 저장소에서 작동하며, 일반 딥 단계가 <code>MEMORY.md</code>로 졸업할 수 있는 것을 결정할 때 사용합니다.</li><li><strong>기반 백필</strong>은 히스토리 <code>memory/YYYY-MM-DD.md</code> 메모를 독립 실행형 일 파일로 읽고 구조화된 검토 출력을 <code>DREAMS.md</code>에 씁니다.</li></ul><p>기반 백필은 <code>MEMORY.md</code>를 수동으로 편집하지 않고 오래된 메모를 재생하고 시스템이 내구성 있다고 생각하는 것을 검사하려는 경우에 유용합니다.</p><p>다음을 사용할 때:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rem-backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./memory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stage-short-term</span></span></code></pre></div><p>기반 내구성 후보가 직접 승격되지 않습니다. 일반 딥 단계가 이미 사용하는 동일한 단기 드리밍 저장소에 준비됩니다. 이는 다음을 의미합니다:</p><ul><li><code>DREAMS.md</code>는 사람이 검토하는 서피스로 유지됩니다.</li><li>단기 저장소는 머신 대면 순위 서피스로 유지됩니다.</li><li><code>MEMORY.md</code>는 여전히 딥 승격으로만 씁니다.</li></ul><p>재생이 유용하지 않다고 결정하면 일반 일기 항목이나 일반 회상 상태를 건드리지 않고 준비된 아티팩트를 제거할 수 있습니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rem-backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rollback</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rem-backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rollback-short-term</span></span></code></pre></div><h2 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 인덱스 상태 및 프로바이더 확인</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;query&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 커맨드 라인에서 검색</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> index</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 인덱스 재빌드</span></span></code></pre></div><h2 id="추가-읽기" tabindex="-1">추가 읽기 <a class="header-anchor" href="#추가-읽기" aria-label="Permalink to &quot;추가 읽기&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/memory-builtin">내장 메모리 엔진</a> -- 기본 SQLite 백엔드</li><li><a href="/openclaw-docs-ko/concepts/memory-qmd">QMD 메모리 엔진</a> -- 고급 로컬 우선 사이드카</li><li><a href="/openclaw-docs-ko/concepts/memory-honcho">Honcho 메모리</a> -- AI 네이티브 크로스 세션 메모리</li><li><a href="/openclaw-docs-ko/plugins/memory-wiki">메모리 위키</a> -- 컴파일된 지식 볼트 및 위키 네이티브 도구</li><li><a href="/openclaw-docs-ko/concepts/memory-search">메모리 검색</a> -- 검색 파이프라인, 프로바이더, 조정</li><li><a href="/openclaw-docs-ko/concepts/dreaming">드리밍 (실험적)</a> -- 단기 회상에서 장기 메모리로 백그라운드 승격</li><li><a href="/openclaw-docs-ko/reference/memory-config">메모리 구성 참조</a> -- 모든 구성 설정</li><li><a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a> -- 컴팩션이 메모리와 상호작용하는 방법</li></ul>`,49)])])}const m=i(l,[["render",t]]);export{k as __pageData,m as default};
